    def make_args(self, switch, mismatch_seed, gumbel_temp, hard_gumbel):
        """Sample hardware mismatch for A (complex polar) and B (multiplicative)."""
        key = jrandom.PRNGKey(mismatch_seed)
        k1, k2, k3 = jrandom.split(key, 3)
        sigma = 0.05

        _Are = self.a_trainable[0:8]
        _Aim = self.a_trainable[8:16]
        _B   = self.a_trainable[16:272].reshape((16, 16))

        # A mismatch: complex polar — magnitude drift + phase drift
        # Matches _S4DLayer.resample_mismatch() convention.
        mag   = jnp.sqrt(_Are ** 2 + _Aim ** 2)
        angle = jnp.arctan2(_Aim, _Are)
        new_mag   = mag   * (1.0 + sigma * jrandom.normal(k1, (8,)))
        new_angle = angle +         sigma * jrandom.normal(k2, (8,))
        _Are_m = new_mag * jnp.cos(new_angle)
        _Aim_m = new_mag * jnp.sin(new_angle)

        # B mismatch: multiplicative per-element (crossbar MVM)
        _B_m = _B * (1.0 + sigma * jrandom.normal(k3, (16, 16)))

        return (_Are_m, _Aim_m, _B_m)

    def ode_fn(self, t, h, args):
        """dh/dt = [A_re*h_re - A_im*h_im, A_im*h_re + A_re*h_im]  (u=0 autonomous)."""
        A_re, A_im, B = args
        h_re = h[:8]
        h_im = h[8:]
        dh_re = A_re * h_re - A_im * h_im
        dh_im = A_im * h_re + A_re * h_im
        # To inject input u (d_model-dim): uncomment and pass u in initial state
        # Bu = B @ u;  dh_re += Bu[:8];  dh_im += Bu[8:]
        return jnp.concatenate([dh_re, dh_im])

    def noise_fn(self, t, h, args):
        return jnp.zeros(16)

    def readout(self, y):
        """Return raw h = [h_re, h_im] at final time. Apply self.C_weight for y."""
        return y[-1]   # shape: (16,)


