    h0 = jnp.zeros(16)
    time_info = TimeInfo(t0=0.0, t1=1.0, dt0=0.01, saveat=jnp.array([1.0]))
    h_final = ckt(time_info, h0, switch=jnp.array([]), args_seed=42, noise_seed=43)
    print(f'h_final shape: {h_final.shape}')  # (16,)
